+import { type AnyColumn, Column } from '~/column.ts';
+import { is } from '~/entity.ts';
+import { type SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type WindowValue = SQLWrapper;
+export type WindowFrameBoundary = { readonly kind: 'unboundedPreceding' | 'preceding' | 'currentRow' | 'following' | 'unboundedFollowing'; readonly value?: number };
+export type WindowFrame = { readonly unit: 'rows' | 'range'; readonly from: WindowFrameBoundary; readonly to: WindowFrameBoundary };
+export type WindowSpec = { partitionBy?: WindowValue | WindowValue[]; orderBy?: WindowValue | WindowValue[]; frame?: WindowFrame };
+
+export const unboundedPreceding: WindowFrameBoundary = { kind: 'unboundedPreceding' };
+export const currentRow: WindowFrameBoundary = { kind: 'currentRow' };
+export const unboundedFollowing: WindowFrameBoundary = { kind: 'unboundedFollowing' };
+
+function position(name: string, value: number): WindowFrameBoundary {
+	if (!Number.isInteger(value) || value < 0) throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+	return { kind: name as 'preceding' | 'following', value };
+}
+export function preceding(value: number): WindowFrameBoundary { return position('preceding', value); }
+export function following(value: number): WindowFrameBoundary { return position('following', value); }
+
+function boundaryOrder(boundary: WindowFrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unboundedPreceding': return -Infinity;
+		case 'preceding': return -boundary.value!;
+		case 'currentRow': return 0;
+		case 'following': return boundary.value!;
+		case 'unboundedFollowing': return Infinity;
+	}
+}
+function frame(unit: WindowFrame['unit'], spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	if (boundaryOrder(spec.from) > boundaryOrder(spec.to)) throw new Error('Window frame "from" boundary cannot be ordered after "to" boundary');
+	return { unit, ...spec };
+}
+export function rows(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame { return frame('rows', spec); }
+export function range(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame { return frame('range', spec); }
+
+function renderBoundary(boundary: WindowFrameBoundary): SQL {
+	switch (boundary.kind) {
+		case 'unboundedPreceding': return sql.raw('unbounded preceding');
+		case 'currentRow': return sql.raw('current row');
+		case 'unboundedFollowing': return sql.raw('unbounded following');
+		case 'preceding': return sql.raw(`${boundary.value} preceding`);
+		case 'following': return sql.raw(`${boundary.value} following`);
+	}
+}
+function list(value: WindowValue | WindowValue[]): WindowValue[] { return Array.isArray(value) ? value : [value]; }
+function over(spec: WindowSpec | string): SQL {
+	if (typeof spec === 'string') return sql` over ${sql.identifier(spec)}`;
+	const parts: SQL[] = [];
+	if (spec.partitionBy) parts.push(sql`partition by ${sql.join(list(spec.partitionBy), sql`, `)}`);
+	if (spec.orderBy) parts.push(sql`order by ${sql.join(list(spec.orderBy), sql`, `)}`);
+	if (spec.frame) parts.push(sql`${sql.raw(spec.frame.unit)} between ${renderBoundary(spec.frame.from)} and ${renderBoundary(spec.frame.to)}`);
+	return sql` over (${sql.join(parts, sql` `)})`;
+}
+
+export class WindowFunction<T> implements SQLWrapper {
+	constructor(private readonly expression: SQL<T>) {}
+	over(spec: WindowSpec | string): SQL<T> { return sql`${this.expression}${over(spec)}` as SQL<T>; }
+	getSQL(): SQL<T> { return this.expression; }
+}
+function fn<T>(name: string, args: SQLWrapper[] = []): WindowFunction<T> { return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})` as SQL<T>); }
+function literal(value: number): SQL { return sql.raw(String(value)); }
+function positive(name: string, value: number): void { if (!Number.isInteger(value) || value <= 0) throw new Error(`${name}() requires a positive integer; received ${value}`); }
+
+export const rowNumber = (): WindowFunction<number> => fn('row_number');
+export const rank = (): WindowFunction<number> => fn('rank');
+export const denseRank = (): WindowFunction<number> => fn('dense_rank');
+export function ntile(buckets: number): WindowFunction<number> { positive('ntile', buckets); return fn('ntile', [literal(buckets)]); }
+export const percentRank = (): WindowFunction<number> => fn('percent_rank');
+export const cumeDist = (): WindowFunction<number> => fn('cume_dist');
+
+type ValueType<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer U> ? U : unknown;
+export function lag<T extends SQLWrapper>(value: T, offset?: number): WindowFunction<ValueType<T> | null>;
+export function lag<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<ValueType<T> | ValueType<TDefault>>;
+export function lag(value: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> { return fn('lag', [value, ...(offset === undefined ? [] : [literal(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]); }
+export function lead<T extends SQLWrapper>(value: T, offset?: number): WindowFunction<ValueType<T> | null>;
+export function lead<T extends SQLWrapper, TDefault extends SQLWrapper>(value: T, offset: number | undefined, defaultValue: TDefault): WindowFunction<ValueType<T> | ValueType<TDefault>>;
+export function lead(value: SQLWrapper, offset?: number, defaultValue?: SQLWrapper): WindowFunction<unknown> { return fn('lead', [value, ...(offset === undefined ? [] : [literal(offset)]), ...(defaultValue === undefined ? [] : [defaultValue])]); }
+export function firstValue<T extends SQLWrapper>(value: T): WindowFunction<ValueType<T> | null> { return fn('first_value', [value]); }
+export function lastValue<T extends SQLWrapper>(value: T): WindowFunction<ValueType<T> | null> { return fn('last_value', [value]); }
+export function nthValue<T extends SQLWrapper>(value: T, n: number): WindowFunction<ValueType<T> | null> { positive('nthValue', n); return fn('nth_value', [value, literal(n)]); }
+export function windowSum(value: SQLWrapper): WindowFunction<string | null> { return fn('sum', [value]); }
+export function windowAvg(value: SQLWrapper): WindowFunction<string | null> { return fn('avg', [value]); }
+export function windowMax<T extends SQLWrapper>(value: T): WindowFunction<ValueType<T> | null> { return new WindowFunction(sql`max(${value})`.mapWith(is(value, Column) ? value : String) as any); }
+export function windowMin<T extends SQLWrapper>(value: T): WindowFunction<ValueType<T> | null> { return new WindowFunction(sql`min(${value})`.mapWith(is(value, Column) ? value : String) as any); }
+export function windowCount(value?: SQLWrapper): WindowFunction<number> { return new WindowFunction(sql`count(${value ?? sql.raw('*')})`.mapWith(Number)); }
